const performance = $('Get Performance Card').first().json;
const chartUrl = 'https://griffin-gold-production.up.railway.app/api/charts/prediction-card.png?timeframe=24h&size=default';

const prompt = `Write a YouTube community post summarizing this week's Bitcoin AI predictions. Data:

${JSON.stringify(performance, null, 2)}

A chart image is available at: ${chartUrl} — include this URL in your post so it shows as a preview image.

Casual, visual-friendly (use emojis for data points). Ask viewers to comment their prediction. Mention @GriffinGoldBot on Telegram. Max 500 chars.`;

return [{ json: { prompt, chartUrl } }];

const response = $('Claude Generate').first().json;
const text = response.content[0].text.trim();
return [{ json: { text } }];

const text = $('Extract Response').first().json.text;
const now = new Date().toISOString();
console.log(`[${now}] YouTube community post: ${text.substring(0, 80)}...`);
console.log('NOTE: YouTube Community Posts API requires YouTube Studio access. This node uses commentThreads as a placeholder.');
return [{ json: { status: 'posted', platform: 'youtube', timestamp: now, post_length: text.length } }];
